{"code": "import json
import re

# Read business data
result_file = locals()['var_functions.query_db:20']
with open(result_file, 'r') as f:
    business_records = json.load(f)

weekdays = ['Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday']
selected_businesses = []

for business in business_records:
    gmap_id = business.get('gmap_id')
    name = business.get('name')
    hours_str = business.get('hours')
    num_reviews = business.get('num_of_reviews')

    if not hours_str or hours_str == 'None':
        continue

    try:
        hours_list = json.loads(hours_str)
        open_late = False

        for day_info in hours_list:
            if len(day_info) < 2:
                continue
            day = day_info[0]
            hours = day_info[1]

            if day not in weekdays or hours == 'Closed':
                continue

            if hours == 'Open 24 hours':
                open_late = True
                break

            try:
                closing_time = hours.split(u'\u2013')[1]
                match = re.search(r'(\d{1,2})(?::(\d{2}))?(AM|PM)', closing_time)
                if match:
                    hour = int(match.group(1))
                    ampm = match.group(3)

                    if ampm == 'PM' and hour != 12:
                        hour += 12
                    elif ampm == 'AM' and hour == 12:
                        hour = 0

                    if hour >= 18:
                        open_late = True
                        break
            except:
                continue

        if open_late:
            selected_businesses.append({
                'gmap_id': gmap_id,
                'name': name,
                'hours': hours_str,
                'num_of_reviews': num_reviews
            })

    except:
        continue

print('Businesses open after 6PM:', len(selected_businesses))
result = json.dumps(selected_businesses)
print('__RESULT__:')
print(result)"}

